import { useZero } from '@rocicorp/zero/react';
import Decimal from 'decimal.js';
import { useCallback, useEffect, useMemo, useRef, useState } from 'react';

import type { ReceiptLineItem } from '@/models/ReceiptLineItem';
import { getUserDisplayName } from '@/utils/user-display';
import { mutators } from '@/zero/mutators';

import {
  evenShares,
  largestRemainderRound,
  rebalance,
  type ShareEntry,
} from '../utils/split-percent';

const PERSIST_DEBOUNCE_MS = 150;

/**
 * React-layer view of a single share row. Extends the pure {@link ShareEntry}
 * with display-only fields the UI needs (display name, color lookup key).
 */
export type DraftEntry = ShareEntry & {
  receiptUserId: string;
  displayName: string;
};

export type UseSplitPercentArgs = {
  item: ReceiptLineItem;
};

export type UseSplitPercentResult = {
  entries: DraftEntry[];
  roundedPercents: number[];
  handleChange: (assignmentId: string, value: Decimal) => void;
  handleToggleLock: (assignmentId: string) => void;
  handleReset: () => void;
};

/**
 * Owns the React-side orchestration for the "split by percent" tab:
 *
 *   - Seeds local draft state from the assignments coming off the receipt.
 *   - Re-seeds when the underlying assignments change (add/remove/remote update).
 *   - Debounces per-row writes back to Zero so slider drags coalesce into a
 *     single mutator call per row.
 *   - Exposes ready-to-render `entries` and `roundedPercents` plus the three
 *     handlers the view needs.
 *
 * All numerical work is delegated to the pure helpers in `../utils/split-percent`.
 */
export function useSplitPercent({
  item,
}: UseSplitPercentArgs): UseSplitPercentResult {
  const zero = useZero();

  // Only active assignments participate in the split; soft-deleted rows would
  // otherwise skew the even-share fallback and show ghost rows in the UI.
  const activeAssignments = useMemo(
    () => item.assignments.filter((assignment) => !assignment.deletedAt),
    [item.assignments]
  );

  // Build a stable key that changes whenever any assignment id, share, or
  // lock flag changes. Used to re-seed local state from the source of truth.
  const seedKey = useMemo(
    () =>
      activeAssignments
        .map(
          (assignment) =>
            `${assignment.id}:${assignment.sharePercentage?.toString() ?? 'null'}:${assignment.locked ? 1 : 0}`
        )
        .join('|'),
    [activeAssignments]
  );

  // Derive the initial draft entries from the receipt's assignments. Rows
  // without an explicit share fall back to an even split across participants.
  const seedEntries = useMemo<DraftEntry[]>(() => {
    const participantCount = activeAssignments.length;
    const fallbackShare = evenShares(participantCount);

    return activeAssignments.map((assignment) => {
      let share: Decimal;
      if (assignment.sharePercentage != null) {
        // Persisted custom share exists → honor it.
        share = assignment.sharePercentage;
      } else {
        // No persisted share yet → seed from the even-split fallback.
        share = fallbackShare;
      }

      return {
        id: assignment.id,
        receiptUserId: assignment.receiptUserId,
        displayName: getUserDisplayName(assignment),
        share,
        locked: assignment.locked,
      };
    });
  }, [activeAssignments]);

  const [entries, setEntries] = useState<DraftEntry[]>(seedEntries);

  // Re-seed whenever the upstream assignments change so remote edits and
  // add/remove operations are reflected locally.
  useEffect(() => {
    setEntries(seedEntries);
  }, [seedKey, seedEntries]);

  // Per-assignment debounce timers. Kept in a ref so re-renders don't reset
  // pending writes mid-flight.
  const persistTimers = useRef<Map<string, ReturnType<typeof setTimeout>>>(
    new Map()
  );

  useEffect(() => {
    const timers = persistTimers.current;
    return () => {
      for (const timer of timers.values()) {
        clearTimeout(timer);
      }
      timers.clear();
    };
  }, []);

  const persistShare = useCallback(
    (assignmentId: string, share: Decimal) => {
      // Replace any in-flight timer for this row so rapid slider moves
      // coalesce into a single mutator call.
      const existing = persistTimers.current.get(assignmentId);
      if (existing) {
        clearTimeout(existing);
      }

      const timer = setTimeout(() => {
        void zero.mutate(
          mutators.assignments.update({
            id: assignmentId,
            share_percentage: share.toNumber(),
          })
        );
        persistTimers.current.delete(assignmentId);
      }, PERSIST_DEBOUNCE_MS);

      persistTimers.current.set(assignmentId, timer);
    },
    [zero]
  );

  const persistChangedShares = useCallback(
    (next: DraftEntry[], previous: DraftEntry[]) => {
      // Diff each row so we only schedule a write when its share actually
      // moved. Sibling rebalancing legitimately touches every unlocked row.
      for (const entry of next) {
        const prev = previous.find((candidate) => candidate.id === entry.id);
        if (!prev || !prev.share.equals(entry.share)) {
          persistShare(entry.id, entry.share);
        }
      }
    },
    [persistShare]
  );

  const handleChange = useCallback(
    (assignmentId: string, value: Decimal) => {
      setEntries((prev) => {
        // Delegate the math to the pure module and persist any row whose
        // share ended up different from its previous value.
        const next = rebalance(prev, assignmentId, value) as DraftEntry[];
        persistChangedShares(next, prev);
        return next;
      });
    },
    [persistChangedShares]
  );

  const handleToggleLock = useCallback(
    (assignmentId: string) => {
      setEntries((prev) => {
        // Flip the lock flag for the targeted row only.
        const next = prev.map((entry) => {
          if (entry.id === assignmentId) {
            return { ...entry, locked: !entry.locked };
          }
          return entry;
        });

        // Mirror the new lock state to Zero so it persists.
        const target = next.find((entry) => entry.id === assignmentId);
        if (target) {
          void zero.mutate(
            mutators.assignments.update({
              id: assignmentId,
              locked: target.locked,
            })
          );
        }

        return next;
      });
    },
    [zero]
  );

  const handleReset = useCallback(() => {
    setEntries((prev) => {
      // Reset: every row gets the even share and every lock is cleared.
      const share = evenShares(prev.length);
      const next = prev.map((entry) => ({
        ...entry,
        share,
        locked: false,
      }));

      // Fire-and-forget a write for every row so the persisted state matches
      // what the user sees. This bypasses the debounce intentionally — a
      // reset is a single discrete action, not a drag.
      const sharePercentage = share.toNumber();
      for (const entry of next) {
        // Cancel any pending debounced write so it can't clobber this reset.
        const pending = persistTimers.current.get(entry.id);
        if (pending) {
          clearTimeout(pending);
          persistTimers.current.delete(entry.id);
        }
        void zero.mutate(
          mutators.assignments.update({
            id: entry.id,
            share_percentage: sharePercentage,
            locked: false,
          })
        );
      }

      return next;
    });
  }, [zero]);

  // Pre-compute the integer percents shown in the UI so the component layer
  // never has to deal with rounding math directly.
  const roundedPercents = useMemo(
    () => largestRemainderRound(entries.map((entry) => entry.share)),
    [entries]
  );

  return {
    entries,
    roundedPercents,
    handleChange,
    handleToggleLock,
    handleReset,
  };
}

import { Trans, useLingui } from '@lingui/react/macro';
import Decimal from 'decimal.js';
import { Lock, Unlock } from 'lucide-react';
import React from 'react';

import {
  type AvatarChipColor,
  DEFAULT_CHIP_COLOR,
} from '@/components/Receipt/utils/avatar-chip-colors';
import { formatCurrency } from '@/components/Receipt/utils/format-currency';
import { calculations } from '@/components/Receipt/utils/receipt-calculation';
import { Avatar, AvatarFallback } from '@/components/ui/avatar';
import { Button } from '@/components/ui/button';
import { Slider } from '@/components/ui/slider';
import { getInitials } from '@/lib/get-initials';
import { cn } from '@/lib/utils';
import type { ReceiptLineItem } from '@/models/ReceiptLineItem';

import { useSplitPercent } from './hooks/useSplitPercent';

interface SplitPercentTabProps {
  item: ReceiptLineItem;
  chipColors: Map<string, AvatarChipColor>;
  formPricePerItem: Decimal;
  formQuantity: Decimal;
}

const SplitPercentTab: React.FC<SplitPercentTabProps> = ({
  item,
  chipColors,
  formPricePerItem,
  formQuantity,
}) => {
  const { t } = useLingui();
  const {
    entries,
    roundedPercents,
    handleChange,
    handleToggleLock,
    handleReset,
  } = useSplitPercent({ item });

  const itemTotal = calculations.pretax.getIndividualItemTotalPrice(item, {
    pricePerItem: formPricePerItem,
    quantity: formQuantity,
  });

  if (entries.length < 2) {
    return (
      <div className="rounded-md p-4 text-center text-sm text-muted-foreground">
        <Trans>Assign 2+ people to customize the split.</Trans>
      </div>
    );
  }

  return (
    <div className="flex flex-col gap-6 p-2">
      <ul className="flex flex-col gap-5">
        {entries.map((entry, idx) => {
          const chipColor =
            chipColors.get(entry.receiptUserId) ?? DEFAULT_CHIP_COLOR;
          const dollar = itemTotal.mul(entry.share).div(100);
          const percentDisplay = roundedPercents[idx] ?? 0;
          return (
            <li key={entry.id} className="flex flex-col gap-2">
              <div className="flex items-center gap-3">
                <Avatar
                  className={cn('ring-1', chipColor.ring)}
                  title={entry.displayName}
                >
                  <AvatarFallback className={cn(chipColor.bg, chipColor.text)}>
                    {getInitials(entry.displayName)}
                  </AvatarFallback>
                </Avatar>
                <span className="flex-1 truncate">{entry.displayName}</span>
                <div
                  className={cn(
                    'flex items-center gap-1 rounded-full bg-muted px-3 py-1',
                    entry.locked && 'opacity-60'
                  )}
                >
                  <input
                    type="number"
                    min={0}
                    max={100}
                    value={percentDisplay}
                    disabled={entry.locked}
                    onChange={(event) => {
                      const parsed = Number(event.target.value);
                      if (Number.isFinite(parsed)) {
                        // Only forward finite numbers so a partially-typed or
                        // cleared input doesn't blow up the rebalance math.
                        handleChange(entry.id, new Decimal(parsed));
                      }
                    }}
                    className="w-10 bg-transparent text-right text-base outline-none md:text-sm"
                    aria-label={t`${entry.displayName} percent`}
                  />
                  <span className="text-sm text-muted-foreground">%</span>
                </div>
                <span className="w-16 text-right tabular-nums">
                  {formatCurrency(dollar)}
                </span>
              </div>
              <div className="flex items-center gap-3">
                <Slider
                  value={[entry.share.toNumber()]}
                  min={0}
                  max={100}
                  step={1}
                  disabled={entry.locked}
                  onValueChange={(vals) =>
                    handleChange(entry.id, new Decimal(vals[0] ?? 0))
                  }
                  className="flex-1"
                  aria-label={t`${entry.displayName} share slider`}
                />
                <Button
                  type="button"
                  variant={entry.locked ? 'default' : 'secondary'}
                  size="icon"
                  className="size-11 shrink-0"
                  onClick={() => handleToggleLock(entry.id)}
                  aria-label={
                    entry.locked
                      ? t`Unlock ${entry.displayName}`
                      : t`Lock ${entry.displayName}`
                  }
                  title={
                    entry.locked
                      ? t`Unlock ${entry.displayName}`
                      : t`Lock ${entry.displayName}`
                  }
                >
                  {entry.locked ? <Lock /> : <Unlock />}
                </Button>
              </div>
            </li>
          );
        })}
      </ul>
      <div className="flex justify-center">
        <Button type="button" variant="link" size="sm" onClick={handleReset}>
          <Trans>Reset to even split</Trans>
        </Button>
      </div>
    </div>
  );
};

export default SplitPercentTab;

import Decimal from 'decimal.js';
import { describe, expect, it } from 'vitest';

import {
  itemHasCustomShares,
  planAddRebalance,
  planRemoveRebalance,
  type RebalanceAssignment,
  type SiblingShareUpdate,
} from './rebalance-shares';

// Small helpers keep the test cases concise and readable.
const decimal = (value: number | string) => new Decimal(value);

const makeAssignment = (
  id: string,
  share: number | string | null,
  locked = false
): RebalanceAssignment => ({
  id,
  sharePercentage: share == null ? null : decimal(share),
  locked,
});

// Sum helper used by the "everything still totals 100" assertions.
const sumUpdates = (updates: SiblingShareUpdate[]): number =>
  updates.reduce((total, update) => total + update.share_percentage, 0);

describe('itemHasCustomShares', () => {
  it('returns false for an empty list', () => {
    expect(itemHasCustomShares([])).toBe(false);
  });

  it('returns false when every assignment has a null share', () => {
    expect(
      itemHasCustomShares([
        makeAssignment('a', null),
        makeAssignment('b', null),
      ])
    ).toBe(false);
  });

  it('returns true when at least one assignment has a non-null share', () => {
    expect(
      itemHasCustomShares([makeAssignment('a', null), makeAssignment('b', 50)])
    ).toBe(true);
  });
});

describe('planAddRebalance', () => {
  it('returns null when no sibling has a custom share', () => {
    expect(
      planAddRebalance([makeAssignment('a', null), makeAssignment('b', null)])
    ).toBeNull();
  });

  it('rescales three equal unlocked siblings and gives newcomer a fair 25', () => {
    const result = planAddRebalance([
      makeAssignment('a', decimal(100).div(3).toString()),
      makeAssignment('b', decimal(100).div(3).toString()),
      makeAssignment('c', decimal(100).div(3).toString()),
    ]);

    expect(result).not.toBeNull();
    expect(result!.warning).toBeNull();
    expect(result!.newcomerShare).toBeCloseTo(25, 10);

    for (const update of result!.siblingUpdates) {
      expect(update.share_percentage).toBeCloseTo(25, 10);
    }

    expect(
      sumUpdates(result!.siblingUpdates) + result!.newcomerShare
    ).toBeCloseTo(100, 10);
  });

  it('caps the newcomer at headroom when locked siblings limit the budget', () => {
    const result = planAddRebalance([
      makeAssignment('a', 60, true),
      makeAssignment('b', 40, false),
    ]);

    expect(result).not.toBeNull();
    expect(result!.warning).toBeNull();
    // Fair = 100/3 ≈ 33.33, headroom = 40 → newcomer gets the smaller (fair).
    expect(result!.newcomerShare).toBeCloseTo(100 / 3, 10);
    // Only the unlocked sibling appears in updates; it absorbs the remaining headroom.
    expect(result!.siblingUpdates).toHaveLength(1);
    expect(result!.siblingUpdates[0].id).toBe('b');
    expect(result!.siblingUpdates[0].share_percentage).toBeCloseTo(
      40 - 100 / 3,
      10
    );
  });

  it('returns the fully-locked warning when locked shares already sum to 100', () => {
    const result = planAddRebalance([makeAssignment('a', 100, true)]);

    expect(result).toEqual({
      newcomerShare: 0,
      newcomerLocked: false,
      siblingUpdates: [],
      warning: 'fully-locked',
    });
  });

  it('returns the fully-locked warning when every sibling is locked (even with sub-100 total)', () => {
    const result = planAddRebalance([
      makeAssignment('a', 40, true),
      makeAssignment('b', 40, true),
    ]);

    expect(result!.warning).toBe('fully-locked');
    expect(result!.newcomerShare).toBe(0);
    expect(result!.siblingUpdates).toEqual([]);
  });

  it('splits remaining evenly when unlocked siblings sum to zero and locks leave headroom', () => {
    const result = planAddRebalance([
      makeAssignment('a', 0, false),
      makeAssignment('b', 0, false),
      makeAssignment('c', 50, true),
    ]);

    expect(result!.warning).toBeNull();
    // Fair = 100/4 = 25, headroom = 50, newcomer = 25, remaining = 25, split evenly = 12.5 each.
    expect(result!.newcomerShare).toBeCloseTo(25, 10);
    expect(result!.siblingUpdates).toHaveLength(2);
    expect(result!.siblingUpdates[0].share_percentage).toBeCloseTo(12.5, 10);
    expect(result!.siblingUpdates[1].share_percentage).toBeCloseTo(12.5, 10);
  });
});

describe('planRemoveRebalance', () => {
  it('returns null when the removed assignment had no custom share', () => {
    expect(
      planRemoveRebalance(makeAssignment('a', null), [makeAssignment('b', 50)])
    ).toBeNull();
  });

  it('returns null when no sibling remains', () => {
    expect(planRemoveRebalance(makeAssignment('a', 100), [])).toBeNull();
  });

  it('distributes the removed share proportionally to unlocked siblings', () => {
    const updates = planRemoveRebalance(makeAssignment('a', 30), [
      makeAssignment('b', 40),
      makeAssignment('c', 30),
    ]);

    expect(updates).not.toBeNull();
    expect(updates).toHaveLength(2);
    // 40 + (40/70)*30 ≈ 57.142857; 30 + (30/70)*30 ≈ 42.857143; sum ≈ 100.
    expect(updates![0].share_percentage).toBeCloseTo(40 + (40 / 70) * 30, 10);
    expect(updates![1].share_percentage).toBeCloseTo(30 + (30 / 70) * 30, 10);
    expect(sumUpdates(updates!)).toBeCloseTo(100, 10);
  });

  it('writes an even split across everyone when all remaining siblings are locked', () => {
    const updates = planRemoveRebalance(makeAssignment('a', 40), [
      makeAssignment('b', 30, true),
      makeAssignment('c', 30, true),
    ]);

    expect(updates).not.toBeNull();
    expect(updates).toHaveLength(2);
    expect(updates![0].share_percentage).toBeCloseTo(50, 10);
    expect(updates![1].share_percentage).toBeCloseTo(50, 10);
    // The mutator does a partial update, so `locked: false` must be sent
    // explicitly to clear the locks on the previously-locked siblings.
    expect(updates![0].locked).toBe(false);
    expect(updates![1].locked).toBe(false);
  });

  it('splits the removed share evenly when the unlocked pool sums to zero', () => {
    const updates = planRemoveRebalance(makeAssignment('a', 60), [
      makeAssignment('b', 0, false),
      makeAssignment('c', 0, false),
      makeAssignment('d', 40, true),
    ]);

    expect(updates).not.toBeNull();
    expect(updates).toHaveLength(2);
    // Each unlocked sibling absorbs half of the 60 → 30.
    expect(updates![0].share_percentage).toBeCloseTo(30, 10);
    expect(updates![1].share_percentage).toBeCloseTo(30, 10);
  });
});

import Decimal from 'decimal.js';
import { describe, expect, it } from 'vitest';

import {
  evenShares,
  largestRemainderRound,
  rebalance,
  type ShareEntry,
} from './split-percent';

const d = (value: number | string) => new Decimal(value);

const makeEntry = (
  id: string,
  share: number | string,
  locked = false
): ShareEntry => ({ id, share: d(share), locked });

const sumShares = (entries: ShareEntry[]): Decimal =>
  entries.reduce((sum, entry) => sum.plus(entry.share), new Decimal(0));

describe('largestRemainderRound', () => {
  it('returns [] for empty input', () => {
    expect(largestRemainderRound([])).toEqual([]);
  });

  it('rounds three equal thirds to sum to 100', () => {
    const result = largestRemainderRound([
      d(100).div(3),
      d(100).div(3),
      d(100).div(3),
    ]);

    expect(result.reduce((sum, value) => sum + value, 0)).toBe(100);
    expect(result).toEqual([34, 33, 33]);
  });

  it('leaves already-integer shares unchanged', () => {
    expect(largestRemainderRound([d(50), d(50)])).toEqual([50, 50]);
    expect(largestRemainderRound([d(25), d(25), d(25), d(25)])).toEqual([
      25, 25, 25, 25,
    ]);
  });

  it('preserves input order when distributing the deficit', () => {
    // Floors → [33, 33, 33] (sum 99), deficit 1 → first entry has largest
    // fractional remainder so it should receive the extra percent.
    const result = largestRemainderRound([d('33.5'), d('33.3'), d('33.2')]);

    expect(result).toEqual([34, 33, 33]);
    expect(result.reduce((sum, value) => sum + value, 0)).toBe(100);
  });
});

describe('evenShares', () => {
  it('returns 0 for zero or negative counts', () => {
    expect(evenShares(0).toNumber()).toBe(0);
    expect(evenShares(-5).toNumber()).toBe(0);
  });

  it('returns 100/count as a Decimal', () => {
    expect(evenShares(4).toNumber()).toBe(25);
    expect(evenShares(3).toFixed(4)).toBe(new Decimal(100).div(3).toFixed(4));
  });
});

describe('rebalance', () => {
  it('returns input unchanged when targetId is unknown', () => {
    const entries = [makeEntry('a', 50), makeEntry('b', 50)];

    expect(rebalance(entries, 'missing', d(80))).toBe(entries);
  });

  it('returns input unchanged when target is locked', () => {
    const entries = [makeEntry('a', 50, true), makeEntry('b', 50)];

    expect(rebalance(entries, 'a', d(80))).toBe(entries);
  });

  it('scales unlocked siblings proportionally', () => {
    const entries = [makeEntry('a', 50), makeEntry('b', 50)];
    const next = rebalance(entries, 'a', d(80));

    expect(next.find((entry) => entry.id === 'a')?.share.toNumber()).toBe(80);
    expect(next.find((entry) => entry.id === 'b')?.share.toNumber()).toBe(20);
    expect(sumShares(next).toNumber()).toBe(100);
  });

  it('preserves locked shares and splits remainder among unlocked', () => {
    const entries = [
      makeEntry('a', 40, true),
      makeEntry('b', 30),
      makeEntry('c', 30),
    ];
    const next = rebalance(entries, 'b', d(50));

    expect(next.find((entry) => entry.id === 'a')?.share.toNumber()).toBe(40);
    expect(next.find((entry) => entry.id === 'b')?.share.toNumber()).toBe(50);
    expect(next.find((entry) => entry.id === 'c')?.share.toNumber()).toBe(10);
    expect(sumShares(next).toNumber()).toBe(100);
  });

  it('clamps target to 100 - lockedSum when request exceeds the budget', () => {
    const entries = [
      makeEntry('a', 40, true),
      makeEntry('b', 30),
      makeEntry('c', 30),
    ];
    const next = rebalance(entries, 'b', d(90));

    expect(next.find((entry) => entry.id === 'b')?.share.toNumber()).toBe(60);
    expect(next.find((entry) => entry.id === 'c')?.share.toNumber()).toBe(0);
    expect(next.find((entry) => entry.id === 'a')?.share.toNumber()).toBe(40);
    expect(sumShares(next).toNumber()).toBe(100);
  });

  it('splits remainder evenly when siblings sum to zero', () => {
    const entries = [makeEntry('a', 100), makeEntry('b', 0), makeEntry('c', 0)];
    const next = rebalance(entries, 'a', d(40));

    expect(next.find((entry) => entry.id === 'a')?.share.toNumber()).toBe(40);
    expect(next.find((entry) => entry.id === 'b')?.share.toNumber()).toBe(30);
    expect(next.find((entry) => entry.id === 'c')?.share.toNumber()).toBe(30);
    expect(sumShares(next).toNumber()).toBe(100);
  });

  it('clamps negative requests to zero', () => {
    const entries = [makeEntry('a', 50), makeEntry('b', 50)];
    const next = rebalance(entries, 'a', d(-20));

    expect(next.find((entry) => entry.id === 'a')?.share.toNumber()).toBe(0);
    expect(next.find((entry) => entry.id === 'b')?.share.toNumber()).toBe(100);
  });
});
